// // This module implements a 10-bit synchronous ring counter that decrements its bit to the right by one position on each positive clock edge when the enable signal is high. The counter resets to 1023 when the reset signal (rst) is active.
module ring_counter_enable_10 
(
  input rst,
  input clk,
  input enable,

  output reg [9:0] count
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      count <= 10'b0000000001;
    end 

	else if (enable) 
	begin
      count <= {count[8:0], count[9]};
    end
  end

endmodule
